<template>
  <div class="page-body">
    <div v-if="$route.path.indexOf('detail') === -1 && $route.path.indexOf('process') === -1">
      <SpFilterForm
        :model="params"
        @onSearch="onSearch"
        @onReset="onSearch"
      >
        <SpFilterFormItem
          prop="activity_name"
          label="活動名稱:"
        >
          <el-input
            v-model="params.activity_name"
            placeholder="請輸入活動名稱"
          />
        </SpFilterFormItem>
        <SpFilterFormItem
          prop="create_time"
          label="時間:"
          size="max"
        >
          <el-date-picker
            v-model="params.create_time"
            clearable
            type="datetimerange"
            align="right"
            format="yyyy-MM-dd HH:mm:ss"
            range-separator="至"
            start-placeholder="開始日期"
            end-placeholder="結束日期"
            prefix-icon="null"
            :default-time="defaultTime"
            :picker-options="pickerOptions"
          />
        </SpFilterFormItem>
        <SpFilterFormItem
          prop="is_success"
          label="僅成團訂單:"
        >
          <el-select
            v-model="params.is_success"
            clearable
            placeholder="請選擇"
          >
            <el-option
              v-for="item in processArr"
              :key="item.value"
              size="mini"
              :label="item.title"
              :value="item.value"
            />
          </el-select>
        </SpFilterFormItem>
      </SpFilterForm>

      <div class="action-container">
        <export-tip @exportHandle="exportCommunityOrder">
          <el-button
            type="primary"
            plain
            icon="el-plus-circle"
          >
            導出活動銷售數據
          </el-button>
        </export-tip>
      </div>

      <el-tabs
        v-model="params.activity_status"
        type="card"
        @tab-click="onSearch"
      >
        <el-tab-pane
          v-for="item in activity_status"
          :key="item.value"
          :label="item.title"
          :name="item.value"
        />
        <el-table
          v-loading="loading"
          border
          :data="tableList"
          @selection-change="handleSelectionChange"
        >
          <el-table-column
            type="selection"
            align="center"
            label="全選"
          />
          <el-table-column
            width="100"
            prop="activity_id"
            label="ID"
          />

          <el-table-column
            width="220"
            prop="activity_name"
            label="活動名稱"
          />
          <el-table-column
            prop="total_fee"
            width="120"
            label="實際收入（NT$）"
          >
            <template slot-scope="scope">
              {{ (scope.row.total_fee / 100).toFixed(2) }}
            </template>
          </el-table-column>
          <el-table-column
            prop="total_fee"
            min-width="150"
            label="有效期"
          >
            <template slot-scope="scope">
              <div>{{ scope.row.start_time }}</div>
              <div>~</div>
              <div>{{ scope.row.end_time }}</div>
            </template>
          </el-table-column>

          <el-table-column
            width="220"
            prop="activity_process_msg"
            label="狀態"
          />

          <el-table-column
            width="200"
            prop="activity_delivery_status_msg"
            label="發貨狀態"
          />

          <el-table-column
            label="操作"
            min-width="150"
          >
            <template slot-scope="scope">
              <div class="operating-icons">
                <el-button
                  v-if="
                    scope.row.activity_status == 'success' && scope.row.delivery_status == 'PENDING'
                  "
                  type="text"
                  @click="send(scope.row)"
                >
                  發貨
                </el-button>
              </div>
            </template>
          </el-table-column>
        </el-table>
        <div class="content-padded content-center">
          <el-pagination
            background
            layout="total, sizes, prev, pager, next, jumper"
            :current-page.sync="page.pageIndex"
            :page-sizes="[10, 20, 50]"
            :total="page.total"
            :page-size="page.pageSize"
            @current-change="onCurrentChange"
            @size-change="onSizeChange"
          />
        </div>
      </el-tabs>
    </div>
    <router-view />
  </div>
</template>
<script>
import { mapGetters } from 'vuex'
import mixin from '@/mixins'
import { pageMixin } from '@/mixins'
import { VERSION_STANDARD, isArray, VERSION_B2C, VERSION_IN_PURCHASE } from '@/utils'
import { getCommunityActivity, communityDeliver, communityOrderExport } from '@/api/promotions'
import moment from 'moment'
import { DISTRIBUTION_TYPE, ORDER_STATUS, PICKER_DATE_OPTIONS } from '@/consts'

export default {
  mixins: [mixin, pageMixin],
  data () {
    return {
      loading: false,
      defaultTime: ['00:00:00', '23:59:59'],
      params: {
        activity_name: '',
        activity_status: '',
        time_start_begin: '', //
        time_start_end: ''
      },
      activity_id: [],
      activity_status: [
        {
          title: '全部',
          value: ''
        },
        {
          title: '未開始',
          value: 'waiting'
        },
        {
          title: '進行中',
          value: 'ongoing'
        },
        {
          title: '已結束',
          value: 'end'
        }
      ],
      processArr: [
        {
          title: '是',
          value: 1
        },
        {
          title: '否',
          value: 0
        }
      ],
      pickerOptions: PICKER_DATE_OPTIONS,
      exportData: {},
      activity_id: []
    }
  },

  computed: {
    ...mapGetters(['wheight'])
  },
  mounted () {
    this.fetchList()
  },
  methods: {
    onSearch () {
      this.page.pageIndex = 1
      this.$nextTick(() => {
        this.fetchList()
      })
    },
    getParams () {
      const time = {}
      if (isArray(this.params.create_time) && this.params.create_time.length >= 2) {
        time.time_start_begin = moment(this.params.create_time[0]).unix()
        time.time_start_end = moment(this.params.create_time[1]).unix()
      }
      let params = {
        ...this.params,
        activity_status: this.params.activity_status == 0 ? undefined : this.params.activity_status,
        activity_name: this.params.activity_name,
        create_time: [],
        ...time
      }
      return params
    },
    onReset () {
      this.params = { ...this.initialParams }
      this.onSearch()
    },
    // 切換tab
    handleTabClick (tab, event) {
      this.onSearch()
    },
    dateStrToTimeStamp (str) {
      return Date.parse(new Date(str)) / 1000
    },
    exportCommunityOrder () {
      if (this.activity_id.length) {
        let params = { activity_id: this.activity_id }
        communityOrderExport(params).then((response) => {
          if (response.data.data.status) {
            this.$message({
              type: 'success',
              message: '已加入執行隊列，請在設置-導出列表中下載'
            })
            this.$export_open('normal_community_order')
            return
          } else if (response.data.data.url) {
            this.downloadUrl = response.data.data.url
            this.downloadName = response.data.filename
            this.downloadView = true
          } else {
            this.$message({
              type: 'error',
              message: '無內容可導出 或 執行失敗，請檢查重試'
            })
            return
          }
        })
      } else {
        communityOrderExport(this.params).then((response) => {
          if (response.data.data.status) {
            this.$message({
              type: 'success',
              message: '已加入執行隊列，請在設置-導出列表中下載'
            })
            this.$export_open('normal_community_order')
            return
          } else if (response.data.data.url) {
            this.downloadUrl = response.data.data.url
            this.downloadName = response.data.filename
            this.downloadView = true
          } else {
            this.$message({
              type: 'error',
              message: '無內容可導出 或 執行失敗，請檢查重試'
            })
            return
          }
        })
      }
    },
    handleSelectionChange (rows) {
      this.activity_id = []
      if (rows) {
        rows.forEach((row) => {
          if (row) {
            this.activity_id.push(row.activity_id)
          }
        })
      }
    },
    async fetchList () {
      this.loading = true
      const { pageIndex: page, pageSize } = this.page
      let params = {
        page,
        pageSize,
        ...this.getParams()
      }
      const { list, total_count } = await this.$api.promotions.getCommunityActivity(params)
      this.tableList = list
      this.page.total = total_count
      this.loading = false
    },

    send (row) {
      var msg = '此操作發貨, 是否繼續?'
      this.$confirm(msg, '提示', {
        cancelButtonText: '取消',
        confirmButtonText: '確定',
        type: 'warning',
        beforeClose: (action, instance, done) => {
          if (action === 'confirm') {
            communityDeliver({ activity_id: row.activity_id }).then((response) => {
              this.fetchList()
              this.$message({
                message: '發貨成功',
                type: 'success',
                duration: 5 * 1000
              })
            })
          }
          done()
        }
      })
    }
  }
}
</script>
<style lang="scss" scope>
.sp-filter-form {
  margin-bottom: 16px;
}
</style>
